description:
When running an aggregated query in the node driver and streaming the results the driver actually streams the entire collection into the data event rather than the results of the query.

{code}
// Create a cursor stream.
var stream = locations.aggregate([
     {
         $match: {
            locationID: { $in: location_ids },
            distance: { $lt: 0.25 }
         }
     },
     { $group: { _id: { userID: '$userID'} } }
], { allowDiskUse: true, cursor: 1 });

// Send errors to papertrail in production and just log for development.
stream.on('error', dealWithError);

// Push found records to an array for processing later.
stream.on('data', dealWithUser);

// When there is no more data, finish up.
stream.on('end', aggregateStreamClosed);
{code}

If I remove the cursor: 1 and add the callback it works as expected.

{code}
locations.aggregate([
     {
         $match: {
            locationID: { $in: location_ids },
            distance: { $lt: 0.25 }
         }
     },
     { $group: { _id: { userID: '$userID'} } }
], { allowDiskUse: true }, dealWithDevice);
{code}

I discover this issue when investigating NODE-293: https://jira.mongodb.org/browse/NODE-293

I am not sure if document is accurate, it states fullResult is false by default, thus I assume insert by default only return status and affected rows.

but as you can see, the result is quite the opposite, insert returns inserted document by default, while fullResult: true cause it to return affected rows...

{code:javascript}
var mongodb = require('mongodb');

mongodb.MongoClient.connect('mongodb://localhost/test', function(err, db) {
  if (err) throw err;

  var col = db.collection('test');

  col.insert({b:1}, function(err, doc) {
    if (err) throw err;

    console.log('inserted', doc);
  });

  col.insert({c:1}, {fullResult: false}, function(err, doc) {
    if (err) throw err;

    console.log('inserted', doc);
  });

  col.insert({d:1}, {fullResult: true}, function(err, doc) {
    if (err) throw err;

    console.log('inserted', doc);
  });
{code}

